import struct
from bitstring import BitArray



def header_parser(packet):
    print(packet)

    header = packet[:1]
    header_bits = BitArray(bytes = header).bin
    print(header_bits)

    header_form = header_bits[0]
    fixed_bit = header_bits[1]
    packet_type = header_bits[2:4]
    reserved = header_bits[4:6]
    pn_length = header_bits[5:8]


    return header_form,fixed_bit,packet_type,reserved,pn_length









if __name__ == "__main__":
    data = bytes.fromhex("")
    header_parser(data)